import org.apache.spark.sql.{SparkSession, DataFrame}
import org.apache.spark.sql.catalyst.parser.ParseException

object SparkSQLQueryProcessor {
  def main(args: Array[String]): Unit = {
    val spark = SparkSession.builder()
      .appName("Spark SQL Query Processor")
      .master("local[*]")
      .getOrCreate()

    import spark.implicits._

    // Example data
    val data = Seq(
      (1, "Alice", 25),
      (2, "Bob", 30)
    ).toDF("id", "name", "age")

    data.createOrReplaceTempView("users")

    processSQLQuery(spark, "SELECT * FROM users WHERE age > 25")
    processSQLQuery(spark, "SELECT name FROM users WHERE id = 1")
    processSQLQuery(spark, "SELECT * FROM non_existent_table") // Should handle error gracefully
  }

  def processSQLQuery(spark: SparkSession, userQuery: String): Unit = {
    try {
      val result: DataFrame = spark.sql(userQuery)
      result.show()
    } catch {
      case e: ParseException =>
        println(s"Invalid SQL query: ${e.getMessage}")
      case e: Exception =>
        println(s"An error occurred while processing the query: ${e.getMessage}")
    }
  }
}